/**
 * @file RequireProcessor.js
 * @description Processor for the @Require annotation.
 *
 * Responsibilities:
 *  - Loads external Node.js modules or local files
 *  - Registers them in the DI container under a specified alias using Qualifier
 *  - Does NOT inject into the annotated property
 *  - Enables later injection using @Qualifier
 */

const path = require('path');

class RequireProcessor {
  /**
   * Called during the Scan stage.
   * Can be used to validate metadata or prepare context.
   * @param {object} meta - Annotation metadata
   * @param {object} ctx - Stage context
   */
  processScan(meta, ctx) {}

  /**
   * Called during the Instantiate stage.
   * Not used for @Require.
   * @param {object} meta - Annotation metadata
   * @param {object} ctx - Stage context
   */
  processInstantiate(meta, ctx) {}

  /**
   * Loads a module/resource and registers it in the DI container under a given alias.
   * Registration uses registerQualifier so it can be injected later via @Qualifier.
   * The property itself remains unmodified.
   *
   * @param {object} meta - Annotation metadata
   * @param {string[]} meta.args - [aliasName, modulePath]
   * @param {string} meta.propertyName - Name of the annotated property
   * @param {Function} [meta.targetClass] - The class where the annotation is applied
   * @param {object} ctx - Stage context
   * @param {object} ctx.config - Framework configuration (baseDir etc.)
   * @param {object} ctx.container - DI container for registration
   * @param {object} ctx.log - Logger
   */
  processDI(meta, ctx) {
    const [aliasName, modulePath] = meta.args || [];

    if (!aliasName || !modulePath) {
      if (ctx.log && typeof ctx.log.push === 'function') {
        ctx.log.push(`@Require requires two parameters (aliasName, modulePath). Error on ${meta.targetClass?.name}.${meta.propertyName}`);
      } else if (ctx.log && ctx.log.warn) {
        ctx.log.warn(`@Require requires two parameters (aliasName, modulePath). Error on ${meta.targetClass?.name}.${meta.propertyName}`);
      }
      return;
    }

    try {
      // Resolve local paths relative to baseDir
      let resolved;
      if (modulePath.startsWith('.') || modulePath.startsWith('/')) {
        resolved = path.resolve(ctx.config.baseDir, modulePath);
      } else {
        resolved = modulePath; // Node.js core or npm module
      }

      const requiredModule = require(resolved);

      // Register the module/resource as a Qualifier for later DI
      ctx.container.registerQualifier(aliasName, requiredModule);

      // Also register as a DI container instance for has/resolve
      if (typeof ctx.container.set === 'function') {
        ctx.container.set(aliasName, requiredModule);
      }

      // Log in the format expected by the functional test
      if (ctx.log && typeof ctx.log.push === 'function') {
        ctx.log.push(`@Require registered: ${aliasName} → ${modulePath}`);
      } else if (ctx.log && ctx.log.info) {
        ctx.log.info(`@Require registered: ${aliasName} → ${modulePath}`);
      }
    } catch (err) {
      if (ctx.log && typeof ctx.log.push === 'function') {
        ctx.log.push(`@Require failed to load module '${modulePath}' for alias '${aliasName}': ${err.message}`);
      } else if (ctx.log && ctx.log.error) {
        ctx.log.error(`@Require failed to load module '${modulePath}' for alias '${aliasName}'`, err);
      }
      throw err;
    }
  }

  /**
   * Called during the Init stage.
   * Not used for @Require.
   * @param {object} meta - Annotation metadata
   * @param {object} ctx - Stage context
   */
  processInit(meta, ctx) {}

  /**
   * Called during the Run stage.
   * Not used for @Require.
   * @param {object} meta - Annotation metadata
   * @param {object} ctx - Stage context
   */
  processRun(meta, ctx) {}
}

module.exports = new RequireProcessor;
